{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyPPQdkCx9nrAEEgE5k/n4gK"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":1,"metadata":{"colab":{"base_uri":"https://localhost:8080/"},"id":"6wlSaPMY6vY3","executionInfo":{"status":"ok","timestamp":1777477568245,"user_tz":-330,"elapsed":48,"user":{"displayName":"Nandana S","userId":"09011285804801661207"}},"outputId":"f7cee5ae-3a2c-4de0-e053-2c95795920fa"},"outputs":[{"output_type":"stream","name":"stdout","text":["Grade using []: A\n","Grade using get(): A\n","Non-existing key: Key not found\n","\n","Updated car: {'brand': 'Honda', 'model': 'Amaze', 'year': 2020}\n","\n","Removed value: 60\n","Updated fruits: {'apple': 100, 'orange': 80}\n","\n","popitem 1: ('c', 3)\n","popitem 2: ('b', 2)\n","Remaining: {'a': 1}\n","\n","After deleting age: {'name': 'John', 'city': 'London'}\n","\n","After clear: {}\n","\n","Keys: dict_keys(['India', 'Japan', 'France'])\n","Key: India\n","Key: Japan\n","Key: France\n","\n","Values: dict_values(['Delhi', 'Tokyo', 'Paris'])\n","Values as list: ['Delhi', 'Tokyo', 'Paris']\n","\n","Items: dict_items([('name', 'Asha'), ('age', 20), ('grade', 'A')])\n","Key: name, Value: Asha\n","Key: age, Value: 20\n","Key: grade, Value: A\n","\n","Original: {'x': 10, 'y': 20}\n","Modified copy: {'x': 100, 'y': 20}\n","\n","Fromkeys dict: {'math': 0, 'science': 0, 'english': 0}\n","\n","After setdefault: {'name': 'Anu', 'age': 22, 'city': 'Kochi'}\n","\n","After update: {'a': 1, 'b': 3, 'c': 4}\n","\n","Ravi science marks: 85\n","Updated Meena: {'math': 90, 'science': 95, 'english': 88}\n","\n","Squares: {1: 1, 2: 4, 3: 9, 4: 16, 5: 25, 6: 36, 7: 49, 8: 64, 9: 81, 10: 100}\n","Uppercase dict: {'A': 'APPLE', 'B': 'BALL'}\n","\n","Inventory after operations: {'book': 8, 'bag': 2}\n","Inventory after clear: {}\n"]}],"source":["# -------------------------------\n","# 1. Create and Access\n","# -------------------------------\n","student = {\"name\": \"Arun\", \"age\": 18, \"grade\": \"A\"}\n","\n","print(\"Grade using []:\", student[\"grade\"])\n","print(\"Grade using get():\", student.get(\"grade\"))\n","\n","print(\"Non-existing key:\", student.get(\"marks\", \"Key not found\"))\n","\n","\n","# -------------------------------\n","# 2. Update\n","# -------------------------------\n","car = {\"brand\": \"Honda\", \"model\": \"City\"}\n","\n","car[\"year\"] = 2020\n","car[\"model\"] = \"Amaze\"\n","\n","print(\"\\nUpdated car:\", car)\n","\n","\n","# -------------------------------\n","# 3. pop()\n","# -------------------------------\n","fruits = {\"apple\": 100, \"banana\": 60, \"orange\": 80}\n","\n","removed = fruits.pop(\"banana\")\n","print(\"\\nRemoved value:\", removed)\n","print(\"Updated fruits:\", fruits)\n","\n","\n","# -------------------------------\n","# 4. popitem()\n","# -------------------------------\n","data = {\"a\": 1, \"b\": 2, \"c\": 3}\n","\n","print(\"\\npopitem 1:\", data.popitem())\n","print(\"popitem 2:\", data.popitem())\n","print(\"Remaining:\", data)\n","\n","\n","# -------------------------------\n","# 5. del\n","# -------------------------------\n","person = {\"name\": \"John\", \"age\": 30, \"city\": \"London\"}\n","\n","del person[\"age\"]\n","print(\"\\nAfter deleting age:\", person)\n","\n","\n","# -------------------------------\n","# 6. clear()\n","# -------------------------------\n","temp = {\"x\": 1, \"y\": 2, \"z\": 3}\n","temp.clear()\n","print(\"\\nAfter clear:\", temp)\n","\n","\n","# -------------------------------\n","# 7. keys()\n","# -------------------------------\n","country = {\"India\": \"Delhi\", \"Japan\": \"Tokyo\", \"France\": \"Paris\"}\n","\n","print(\"\\nKeys:\", country.keys())\n","\n","for key in country.keys():\n","    print(\"Key:\", key)\n","\n","\n","# -------------------------------\n","# 8. values()\n","# -------------------------------\n","print(\"\\nValues:\", country.values())\n","\n","values_list = list(country.values())\n","print(\"Values as list:\", values_list)\n","\n","\n","# -------------------------------\n","# 9. items()\n","# -------------------------------\n","student2 = {\"name\": \"Asha\", \"age\": 20, \"grade\": \"A\"}\n","\n","print(\"\\nItems:\", student2.items())\n","\n","for k, v in student2.items():\n","    print(f\"Key: {k}, Value: {v}\")\n","\n","\n","# -------------------------------\n","# 10. copy()\n","# -------------------------------\n","original = {\"x\": 10, \"y\": 20}\n","copy_dict = original.copy()\n","\n","copy_dict[\"x\"] = 100\n","\n","print(\"\\nOriginal:\", original)\n","print(\"Modified copy:\", copy_dict)\n","\n","\n","# -------------------------------\n","# 11. fromkeys()\n","# -------------------------------\n","subjects = [\"math\", \"science\", \"english\"]\n","\n","new_dict = dict.fromkeys(subjects, 0)\n","print(\"\\nFromkeys dict:\", new_dict)\n","\n","\n","# -------------------------------\n","# 12. setdefault()\n","# -------------------------------\n","person2 = {\"name\": \"Anu\", \"age\": 22}\n","\n","person2.setdefault(\"city\", \"Kochi\")\n","person2.setdefault(\"age\", 30)\n","\n","print(\"\\nAfter setdefault:\", person2)\n","\n","\n","# -------------------------------\n","# 13. update()\n","# -------------------------------\n","dict1 = {\"a\": 1, \"b\": 2}\n","dict2 = {\"b\": 3, \"c\": 4}\n","\n","dict1.update(dict2)\n","print(\"\\nAfter update:\", dict1)\n","\n","\n","# -------------------------------\n","# 14. Nested Dictionary\n","# -------------------------------\n","students = {\n","    \"Ravi\": {\"math\": 80, \"science\": 85},\n","    \"Meena\": {\"math\": 90, \"science\": 95}\n","}\n","\n","print(\"\\nRavi science marks:\", students[\"Ravi\"][\"science\"])\n","\n","students[\"Meena\"][\"english\"] = 88\n","print(\"Updated Meena:\", students[\"Meena\"])\n","\n","\n","# -------------------------------\n","# 15. Dictionary Comprehension\n","# -------------------------------\n","squares = {i: i*i for i in range(1, 11)}\n","print(\"\\nSquares:\", squares)\n","\n","letters = {\"a\": \"apple\", \"b\": \"ball\"}\n","upper_letters = {k.upper(): v.upper() for k, v in letters.items()}\n","print(\"Uppercase dict:\", upper_letters)\n","\n","\n","# -------------------------------\n","# 16. Combining Multiple Methods\n","# -------------------------------\n","inventory = {}\n","\n","# Add items\n","inventory[\"pen\"] = 10\n","inventory[\"book\"] = 5\n","inventory[\"bag\"] = 2\n","\n","# Update quantity\n","inventory[\"book\"] = 8\n","\n","# Remove item\n","inventory.pop(\"pen\")\n","\n","print(\"\\nInventory after operations:\", inventory)\n","\n","# Clear dictionary\n","inventory.clear()\n","print(\"Inventory after clear:\", inventory)"]}]}